UPDATE pesantren_kitab SET description_id = 'Kitab fiqih dasar mazhab Syafi''i karya Syaikh Salim bin Sumair Al-Hadhrami, disusun ringkas dalam bentuk enumerasi (rukun, syarat, dan pembatal) sehingga mudah dihafal santri pemula. Membahas dasar-dasar ibadah: rukun Islam dan iman, thaharah (bersuci, wudhu, mandi, tayamum, najis), serta shalat lengkap dengan syarat, rukun, dan sunnahnya. Menjadi kitab pertama di hampir seluruh pesantren Nusantara dan pintu masuk memahami fiqih ibadah harian.' WHERE slug = 'safinah';
UPDATE pesantren_kitab SET description_id = 'Kitab adab menuntut ilmu karya Syaikh Burhanuddin Az-Zarnuji yang mengajarkan bagaimana seorang penuntut ilmu bersikap agar ilmunya berkah dan bermanfaat. Membahas niat belajar, memilih ilmu dan guru, mengagungkan ilmu dan ahlinya, kesungguhan, tawakal, serta hal-hal yang menguatkan dan melemahkan hafalan. Dibaca turun-temurun di pesantren sebagai pembentuk akhlak sebelum dan selama menuntut ilmu.' WHERE slug = 'talimutaliam';
UPDATE pesantren_kitab SET description_id = 'Matan dasar ilmu nahwu (tata bahasa Arab) karya Ibnu Ajurrum Ash-Shanhaji (w. 723 H) dari Maroko, ringkas namun mencakup pokok-pokok kaidah i''rab. Membahas pembagian kalam, tanda-tanda i''rab, marfu''at, manshubat, dan makhfudhat sebagai fondasi membaca kitab kuning. Menjadi jenjang pertama pembelajaran nahwu di pesantren sebelum naik ke Al-Imrithi dan Alfiyah.' WHERE slug = 'jurumiyah';
UPDATE pesantren_kitab SET description_id = 'Nazham akidah Ahlussunnah wal Jama''ah karya Syaikh Ahmad Al-Marzuqi Al-Maliki (w. 1281 H), tersusun dalam 57 bait yang mudah dilagukan dan dihafal. Merangkum 50 sifat wajib, mustahil, dan jaiz bagi Allah dan para rasul, nama-nama 25 nabi, para malaikat, kitab suci, serta peristiwa Isra Mikraj. Menjadi rujukan akidah pemula paling populer di Nusantara.' WHERE slug = 'aqidatulawam';
UPDATE pesantren_kitab SET description_id = 'Nazham agung ilmu nahwu dan sharaf karya Imam Ibnu Malik Al-Andalusi (w. 672 H) yang berisi seribu bait (alfiyah = seribu). Mencakup nyaris seluruh kaidah tata bahasa Arab secara sistematis, dari kalam hingga masalah sharaf yang rumit. Menjadi puncak pembelajaran nahwu di pesantren; santri yang mengkhatamkannya dipandang telah kokoh dalam gramatika Arab.' WHERE slug = 'alfiyah';
UPDATE pesantren_kitab SET description_id = 'Kitab akhlak dan tasawuf amali karya Hujjatul Islam Imam Al-Ghazali (w. 505 H) sebagai gerbang awal menempuh jalan hidayah. Membagi tuntunan menjadi tiga: ketaatan (adab bangun, bersuci, shalat, hingga aktivitas harian), menjauhi maksiat anggota badan, dan adab pergaulan dengan Allah maupun sesama. Ringkas, praktis, dan menjadi bekal amaliah santri sehari-hari.' WHERE slug = 'bidayatulhidayah';
UPDATE pesantren_kitab SET description_id = 'Kitab karya Syaikh Abdullah bin Husain Ba''alawi yang memadukan tiga pilar agama: akidah, fiqih, dan tasawuf dalam satu matan ringkas. Membahas dasar keimanan, kewajiban ibadah (thaharah, shalat, zakat, puasa, haji), serta larangan-larangan dan taubat. Banyak dibaca di pesantren sebagai pelengkap Safinatun Najah karena cakupannya yang menyeluruh namun padat.' WHERE slug = 'sullamtaufiq';
UPDATE pesantren_kitab SET description_id = 'Syarah masyhur atas matan Al-Ghayah wat Taqrib karya Syaikh Ibnu Qasim Al-Ghazi (w. 918 H), menjelaskan fiqih mazhab Syafi''i secara lengkap dan tertib. Membahas seluruh bab ibadah dan muamalah: thaharah, shalat, zakat, puasa, haji, jual beli, waris, nikah, jinayah, hingga peradilan. Menjadi jenjang menengah fiqih pesantren setelah Safinah dan Sullam Taufiq.' WHERE slug = 'fathulqarib';
UPDATE pesantren_kitab SET description_id = 'Kitab fiqih mazhab Syafi''i tingkat lanjut karya Imam An-Nawawi (w. 676 H), ringkasan dari Al-Muharrar milik Ar-Rafi''i dengan tarjih (pemilihan pendapat terkuat). Menjadi rujukan utama fatwa mazhab Syafi''i dan induk banyak syarah besar seperti Mughni al-Muhtaj dan Tuhfah al-Muhtaj. Dikaji santri senior yang telah menguasai fiqih dasar dan menengah.' WHERE slug = 'minhajultalibin';
UPDATE pesantren_kitab SET description_id = 'Kitab tauhid karya ulama Nusantara Syaikh Nawawi Al-Bantani (w. 1314 H), syarah atas risalah tauhid Syaikh Ibrahim Al-Bajuri. Menguraikan sifat-sifat wajib, mustahil, dan jaiz bagi Allah serta para rasul secara jelas dan sistematis. Menjadi salah satu kitab akidah kebanggaan Nusantara yang diajarkan luas di pesantren.' WHERE slug = 'tijandaruri';
UPDATE pesantren_kitab SET description_id = 'Kitab nasihat keagamaan dan tasawuf karya Al-Habib Abdullah bin Alwi Al-Haddad (w. 1132 H), penyusun Ratib Al-Haddad. Berisi nasihat menghidupkan iman, takwa, muraqabah, taubat, ikhlas, dan zuhud dengan bahasa yang menyentuh hati. Dibaca di pesantren dan majelis untuk melembutkan hati dan menguatkan amaliah ruhani.' WHERE slug = 'nashaihuddiniyyah';
UPDATE pesantren_kitab SET description_id = 'Nazham nahwu karya Syaikh Syarafuddin Yahya Al-Imrithi, penyair ulang matan Al-Ajurrumiyyah ke dalam sekitar 254 bait agar lebih mudah dihafal dan dilagukan. Menjadi jembatan antara Al-Jurumiyyah yang ringkas dan Alfiyah yang luas dalam tangga pembelajaran nahwu pesantren. Memperdalam kaidah i''rab sekaligus melatih santri menghafal bait.' WHERE slug = 'imrithi';
UPDATE pesantren_kitab SET description_id = 'Kitab akidah karya Imam Muhammad bin Yusuf As-Sanusi (w. 895 H), dikenal sebagai As-Sanusiyyah, yang menekankan pembuktian akidah dengan dalil akal (burhan). Merangkum sifat wajib, mustahil, dan jaiz bagi Allah dan rasul beserta dalil rasionalnya, serta makna kalimat tauhid. Menjadi rujukan penting kajian ilmu kalam Ahlussunnah di pesantren.' WHERE slug = 'ummulmabrahim';
